class Solution:
    def smallestRepunitDivByK(self, k):
        seen = set()
        r = 0
        length = 0
        while True:
            r = (r * 10 + 1) % k
            length += 1
            if r == 0:
                return length
            if r in seen:
                return -1
            seen.add(r)

